import {
  Box,
  Header,
  Icon,
  Modal,
  StatusBar,
} from '@semparar/design-system-app';
import type { PropsStatusBar } from '@semparar/design-system-app/src/atomic/atoms/StatusBar/Models';
import type { PropsHeader } from '@semparar/design-system-app/src/atomic/molecules/Header/Models';
import { ModalLoadingBox, Text } from '@semparar/design-system-app/fintech';
import React, { FC } from 'react';
import { ScrollView } from 'react-native';

import { eventSelectContent } from '~/constants/functions';
import WrapperKeyboardAvoiding from '../WrapperKeyboardAvoiding';
import { BasicScreenViewProps } from './Models';
import { Container, Overlay } from './styles';

const BasicScreenView: FC<BasicScreenViewProps> = ({
  children,
  title = '',
  hasLeftIcon = true,
  leftIcon = 'icon-back',
  leftIconOnPress = () => {},
  hasRightIcon = false,
  rightIcon = 'icon-close',
  rightIconOnPress = () => {},
  statusBarBg = 'BRAND_BASE_01',
  statusBarProps = {
    barStyle: 'light-content',
  },
  isLoading = false,
  bgColor = 'BRAND_COMPLEMENT_03',
  hasScroll = false,
  hasHeader = true,
  headerTitle,
  scrollViewProps,
  titleColor,
  leftIconColor,
  rightIconColor,
  rightSecondaryIcon,
  rightSecondaryIconNot,
  testID,
  throttle,
  scrollViewRef,
  showValue,
  setShowValue,
  errorButtonOnPress,
  currentRouteName,
  handleGoToHome,
  hasError,
  handleClose,
}) => {
  return (
    <WrapperKeyboardAvoiding>
      <ModalLoadingBox
        onClose={() => null}
        visible={isLoading}
        numberOfLines={1}
        title="Aguarde..."
      />
      <Container testID={testID} bgColor={bgColor}>
        <StatusBar bgColor={statusBarBg as PropsStatusBar['bgColor']} {...statusBarProps} />
        {hasHeader ? (
          <Header
            title={title}
            iconLeft={leftIcon}
            iconRight={rightIcon}
            hideLeftIcon={!hasLeftIcon}
            isOption={hasRightIcon}
            onBack={leftIconOnPress}
            onPressIconRight={rightIconOnPress}
            titleColor={titleColor as PropsHeader['titleColor']}
            iconColorLeft={leftIconColor as PropsHeader['iconColorLeft']}
            iconColorOnOption={rightIconColor as PropsHeader['iconColorOnOption']}
            testID="icon-home-button"
          />
        ) : null}
        {headerTitle ? (
          <Box
            width="100%"
            bgColor="BRAND_COMPLEMENT_01"
            pd="innerLarge"
            direction
            justify="space-between"
          >
            <Text type="subtitleXXXXL" color="BRAND_COMPLEMENT_02">
              {headerTitle}
            </Text>
            <Box direction justify="space-between">
              {rightSecondaryIcon && (
                <Icon
                  mr="middle"
                  onPress={() => setShowValue?.(!showValue)}
                  name={showValue ? rightSecondaryIcon : rightSecondaryIconNot}
                  color="BRAND_COMPLEMENT_02"
                />
              )}
              <Icon
                name={rightIcon}
                color="BRAND_COMPLEMENT_02"
                onPress={rightIconOnPress}
              />
            </Box>
          </Box>
        ) : null}
        {hasScroll ? (
          <ScrollView
            ref={scrollViewRef}
            {...scrollViewProps}
            scrollEnabled={hasScroll}
            scrollEventThrottle={throttle ?? 0}
            contentContainerStyle={{ flexGrow: 1 }}
          >
            {children}
          </ScrollView>
        ) : (
          children
        )}

        {hasError && (
          <Overlay>
            <Modal
              iconBgColor="DENY_COLOR_03"
              visible={hasError}
              icon="icon-circle-alert"
              onPressFirstButton={() => {
                eventSelectContent({
                  content_type: 'cta',
                  content_id: 'tentar_novamente_erro',
                  location_1: 'monetizacao',
                  location_2: 'spmais',
                  location_3: currentRouteName ?? '',
                });
                errorButtonOnPress();
              }}
              onPressSecondButton={handleGoToHome}
              textFirstButton="Tentar novamente"
              textSecondButton="Voltar para Home"
              subTitle="Ops, algo deu errado..."
              colorSubtitle="BRAND_COMPLEMENT_01"
              iconColor="DENY_COLOR_01"
              testID="modalApiError"
              description="Por favor, tente novamente."
              onClose={handleClose}
            />
          </Overlay>
        )}
      </Container>
    </WrapperKeyboardAvoiding>
  );
};

export default BasicScreenView;

import { Button, Box } from '@semparar/design-system-app';
import { Text } from '@semparar/design-system-app/fintech';
import React, { FC } from 'react';
import { Image } from 'react-native';

import ErrorApi from '../../../assets/images/errorApi.png';
import { ApiErrorViewProps } from './Models';
import { Container, Content } from './styles';
import { Icon } from '@semparar/design-system-app';

const ApiErrorView: FC<ApiErrorViewProps> = ({
  onPress,
  title,
  subTitle,
  hasBackToHome,
  isLoading,
  handleNavigateToHome,
  testID,
}) => {
  return (
    <Container testID={testID}>
      <Content>
        {hasBackToHome ? (
          <Box width={100} align="center">
            <Image
              source={ErrorApi}
              style={{
                width: 188,
                height: 188,
              }}
            />
          </Box>
          ) : (
            <Box
              bgColor="DENY_COLOR_03"
              borderColor="DENY_COLOR_01"
              borderRadiusBottomLeft="medium"
              pd="innerMedium"
              borderRadiusBottomRight="medium"
              borderRadiusTopRight="medium"
              borderRadiusTopLeft="medium"
              borderBottomWidth="small"
              borderTopWidth="small"
              borderLeftWidth="small"
              borderRightWidth="small"
            >
              <Icon name="icon-circle-alert" color="DENY_COLOR_01" size="sm" />
            </Box>
          )}

        <Text mt="smaller" type="subtitleXXXXL" align="center">
          {title}
        </Text>

        {!!subTitle && (
          <Text
            align="center"
            mt="xxxxs"
            type="paragraphXXL"
            color="INTENSE_COLOR_03"
          >
            {subTitle}
          </Text>
        )}
      </Content>
      <Button
        testID="apiError_retry-button"
        isLoading={isLoading}
        text={hasBackToHome ? "Tentar novamente" : "Voltar"}
        mb="xs"
        onPress={onPress}
      />
      {
        hasBackToHome && (
          <Button
            mb="xs"
            type="ghostSmall"
            onPress={handleNavigateToHome}
            text="Voltar para a home"
          />
        )
      }
    </Container >
  );
};

export default ApiErrorView;

